})();

const sessionId = toStr($json.session_id || fromFetch.session_id || fromNormalize.session_id || 'default');
const route = toStr($json.route || fromFetch.route || fromNormalize.route || 'pr_qa');
const precheckOriginal = toStr(fromFetch.precheck_original_message || fromNormalize.precheck_original_message || fromFetch.question || fromNormalize.question || '');

const normalizeStatus = (s) => {
  const v = toStr(s)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
    .replace(/\s+/g, '_')
    .replace(/-/g, '_');

  if (v === 'SIM') return 'SIM';
  if (v === 'PARCIAL') return 'PARCIAL';
  if (v === 'NAO' || v === 'N') return 'NAO';
  if (v === 'SEM_EVIDENCIA' || v === 'SEMEVIDENCIA') return 'SEM_EVIDENCIA';
  return '';
};

const tryParseJsonStatus = (raw) => {
  const txt = toStr(raw);
  const candidates = [txt];
  const fenced = txt.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced && fenced[1]) candidates.push(toStr(fenced[1]));

  for (const c of candidates) {
    try {
      const obj = JSON.parse(c);
      if (obj && typeof obj === 'object' && 'status' in obj) {
        const st = normalizeStatus(obj.status);
        if (st) return st;
      }
    } catch (_e) {}
  }
  return '';
};

const parseStatus = (raw) => {
  const txt = toStr(raw);
  const jsonStatus = tryParseJsonStatus(txt);
  if (jsonStatus) return jsonStatus;

  const patterns = [
    /(?:^|\n)\s*[-*]?\s*[*_`"]?status[*_`"]?\s*[:=]\s*[*_`"]?(SIM|PARCIAL|NAO|NÃO|SEM[ _-]?EVIDENCIA)\b/i,
    /"status"\s*:\s*"(SIM|PARCIAL|NAO|NÃO|SEM[ _-]?EVIDENCIA)"/i,
    /\bstatus\b[^\n]{0,80}\b(SIM|PARCIAL|NAO|NÃO|SEM[ _-]?EVIDENCIA)\b/i,
  ];

  for (const re of patterns) {
    const m = txt.match(re);
    if (m && m[1]) {
      const st = normalizeStatus(m[1]);
      if (st) return st;
    }
  }
  return '';
};

let output = text;

const getStore = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (this && typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  throw new Error('[Build PR Chat Reply] static data indisponivel no Code node.');
};

const store = getStore();
if (!store.chatMemory) store.chatMemory = {};
if (!store.chatModes) store.chatModes = {};
if (!store.impactDrafts) store.impactDrafts = {};
if (!store.impactPrecheck) store.impactPrecheck = {};
if (!store.pendingImpactProceed) store.pendingImpactProceed = {};
if (!store.lastSuggestedImpactPayload) store.lastSuggestedImpactPayload = {};
if (!Array.isArray(store.chatMemory[sessionId])) store.chatMemory[sessionId] = [];
if (!('chatModeGlobal' in store)) store.chatModeGlobal = '';
if (!('impactDraftGlobal' in store)) store.impactDraftGlobal = null;
if (!('impactPrecheckGlobal' in store)) store.impactPrecheckGlobal = { done: false, checked_at: null, status: '' };
if (!('pendingImpactProceedGlobal' in store)) store.pendingImpactProceedGlobal = { awaiting: false };
if (!('lastSuggestedImpactPayloadGlobal' in store)) store.lastSuggestedImpactPayloadGlobal = null;

if (route === 'pr_qa_precheck') {
  let status = parseStatus(text);
  const statusFromFallback = !status;
  if (!status) status = 'SEM_EVIDENCIA';

  const precheckPayload = { done: true, status, checked_at: new Date().toISOString() };
  store.impactPrecheck[sessionId] = precheckPayload;
  store.impactPrecheckGlobal = precheckPayload;

  if (status === 'SIM') {
    delete store.impactDrafts[sessionId];
    store.impactDraftGlobal = null;
    delete store.pendingImpactProceed[sessionId];
    store.pendingImpactProceedGlobal = { awaiting: false };
    delete store.lastSuggestedImpactPayload[sessionId];
    store.lastSuggestedImpactPayloadGlobal = null;
    delete store.chatModes[sessionId];
    store.chatModeGlobal = '';

    output = [
      'Verificacao previa concluida: a necessidade ja existe (status SIM).',
      'Nao vou prosseguir com Impact Analysis.',
      '',
      text,
      '',
      'Se quiser iniciar uma nova solicitacao, envie /menu.'
    ].join('\n');
  } else {
    const suggestedPayload = {
      problema: precheckOriginal || 'Necessidade identificada via analise de PRs',
      mudanca: [
        'Prosseguir com implementacao/correcao da necessidade com base na analise de PRs.',
        'Status da analise: ' + status + '.',
        precheckOriginal ? ('Necessidade original: ' + precheckOriginal) : ''
      ].filter(Boolean).join(' '),
      evidencias: [
        'Resultado da analise de PRs: status=' + status + '.',
        text
      ].join('\n\n'),
      restricoes: 'Manter compatibilidade com PRs existentes e evitar regressao funcional.'
    };

    store.lastSuggestedImpactPayload[sessionId] = suggestedPayload;
    store.lastSuggestedImpactPayloadGlobal = suggestedPayload;

    const pending = {
      awaiting: true,
      status,
      analysis_text: text,
      suggested_payload: suggestedPayload,
      created_at: new Date().toISOString()
    };

    store.pendingImpactProceed[sessionId] = pending;
    store.pendingImpactProceedGlobal = pending;

    const header = statusFromFallback
      ? 'Resultado da analise de PRs: SEM_EVIDENCIA (fallback aplicado: Status nao identificado no retorno do LLM).'
      : 'Resultado da analise de PRs: ' + status + '.';

    output = [
      header,
      '',
      text,
      '',
      'Deseja prosseguir com a implementacao?',
      'Se responder SIM, vou acionar o fluxo Impact Analysis com Impact Inputs preenchidos a partir desta analise.',
      'Responda apenas: SIM ou NAO.'
    ].join('\n');
  }
}

store.chatMemory[sessionId].push({ role: 'assistant', content: output, at: new Date().toISOString() });
if (store.chatMemory[sessionId].length > 40) {
  store.chatMemory[sessionId] = store.chatMemory[sessionId].slice(-40);
}

return [{ json: { output } }];

const toStr = (v) => String(v ?? '').trim();
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const getEnv = (key) => {
  try {
    if ($env && $env[key]) return String($env[key]).trim();
  } catch (_e) {}
  try {
    const p = (typeof globalThis !== 'undefined' && globalThis.process && globalThis.process.env)
      ? globalThis.process.env[key]
      : '';
    if (p) return String(p).trim();
  } catch (_e) {}
  return '';
};

const getStore = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (this && typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  return {};
};

const raw = $json || {};

const deepFindMessage = (obj) => {
  const exactKeys = new Set(['chatInput', 'message', 'text', 'input']);

  const direct = [
    obj?.chatInput,
    obj?.message,
    obj?.text,
    obj?.input,
    obj?.body?.chatInput,
    obj?.body?.message,
    obj?.body?.text,
    obj?.body?.input,
    obj?.payload?.chatInput,
    obj?.payload?.message,
    obj?.payload?.text,
    obj?.payload?.input,
    obj?.data?.chatInput,
    obj?.data?.message,
    obj?.data?.text,
    obj?.data?.input,
  ];
  for (const c of direct) {
    const s = toStr(c);
    if (s) return s;
  }

  const queue = [obj];
  const seen = new Set();
  while (queue.length) {
    const cur = queue.shift();
    if (!cur || typeof cur !== 'object') continue;
    if (seen.has(cur)) continue;
    seen.add(cur);
    for (const [k, v] of Object.entries(cur)) {
      if (typeof v === 'string' && exactKeys.has(String(k))) {
        const s = toStr(v);
        if (s) return s;
      } else if (v && typeof v === 'object') {
        queue.push(v);
      }
    }
  }

  // Last-resort fallback for n8n hosted chat payload variants:
  // collect all string leaves and pick the last user-like short text.
  const strings = [];
  const q = [obj];
  const seen2 = new Set();
  while (q.length) {
    const cur = q.shift();
    if (!cur || typeof cur !== 'object') continue;
    if (seen2.has(cur)) continue;
    seen2.add(cur);
    for (const v of Object.values(cur)) {
      if (typeof v === 'string') strings.push(v);
      else if (v && typeof v === 'object') q.push(v);
    }
  }
  const isUiBoilerplate = (s) => {
    const t = norm(s);
    return (
      t.includes('escolha uma opcao para continuar') ||
      t.includes('nova analise de impacto') ||
      t.includes('duvida sobre funcionalidade') ||
      t.includes('correcao de prs abertas') ||
      t.includes('qual problema ou oportunidade essa alteracao resolve') ||
      t.includes('descreva a mudanca como voce espera ver no produto') ||
      t.includes('quais evidencias/criterios de aceite comprovam') ||
      t.includes('limites de prazo, compliance')
    );
  };
  for (let i = strings.length - 1; i >= 0; i--) {
    const s = toStr(strings[i]);
    if (!s) continue;
    if (s.length > 400) continue;
    if (isUiBoilerplate(s)) continue;
    return s;
  }

  return '';
};

const message = deepFindMessage(raw);
const sessionId = toStr(
  raw.chatId ||
  raw.chat_id ||
  raw.conversationId ||
  raw.conversation_id ||
  raw.metadata?.chatId ||
  raw.metadata?.chat_id ||
  raw.metadata?.conversationId ||
  raw.metadata?.conversation_id ||
  raw.sessionId ||
  raw.session_id ||
  raw.chatSessionId ||
  raw.metadata?.sessionId ||
  'default'
);

const runtimeRoot = (typeof globalThis !== 'undefined') ? globalThis : {};
if (!runtimeRoot.__fastrouteChatState) runtimeRoot.__fastrouteChatState = {};
if (!runtimeRoot.__fastrouteChatState.chat) {
  runtimeRoot.__fastrouteChatState.chat = {
    chatModeGlobal: '',
    menuShownGlobal: false,
    impactIntakeGlobal: null,
    chatMemory: {},
  };
}
const runtime = runtimeRoot.__fastrouteChatState.chat;

const store = getStore();
if (!store.chatMemory) store.chatMemory = {};

const readState = (k, fallback) => {
  const s = store[k];
  if (s !== undefined && s !== null) return s;
  const r = runtime[k];
  if (r !== undefined && r !== null) return r;
  return fallback;
};
const writeState = (k, v) => {
  try { store[k] = v; } catch (_e) {}
  runtime[k] = v;
};

const chatModeGlobal = () => toStr(readState('chatModeGlobal', ''));
const menuShownGlobal = () => !!readState('menuShownGlobal', false);
const impactIntakeGlobal = () => readState('impactIntakeGlobal', null);

const getMemory = () => {
  const memStore = store.chatMemory || {};
  const memRun = runtime.chatMemory || {};
  const arr = Array.isArray(memStore[sessionId]) ? memStore[sessionId] : (Array.isArray(memRun[sessionId]) ? memRun[sessionId] : []);
  if (!Array.isArray(memStore[sessionId])) memStore[sessionId] = [...arr];
  if (!Array.isArray(memRun[sessionId])) memRun[sessionId] = [...arr];
  store.chatMemory = memStore;
  runtime.chatMemory = memRun;
  return { memStore, memRun };
};

const pushMemory = (role, content) => {
  const text = toStr(content);
  if (!text) return;
  const { memStore, memRun } = getMemory();
  memStore[sessionId].push({ role, content: text, at: new Date().toISOString() });
  memRun[sessionId].push({ role, content: text, at: new Date().toISOString() });
  if (memStore[sessionId].length > 40) memStore[sessionId] = memStore[sessionId].slice(-40);
  if (memRun[sessionId].length > 40) memRun[sessionId] = memRun[sessionId].slice(-40);
};

const chatHistory = () => {
  const { memStore } = getMemory();
  return memStore[sessionId].slice(-12).map((t) => ({ role: t.role, content: toStr(t.content) }));
};

const menuText = [
  'Escolha uma opcao para continuar (envie apenas 1, 2 ou 3):',
  '1) Nova analise de Impacto',
  '2) Duvida sobre funcionalidade ja implementada',
  '3) Correcao de PRs abertas',
  '',
  'Comandos uteis:',
  '/menu: voltar ao menu',
  '/reset: limpar estado da conversa'
].join('\n');

const encodeState = (state) => {
  try { return encodeURIComponent(JSON.stringify(state || {})); } catch (_e) { return ''; }
};
const decodeState = (token) => {
  try { return JSON.parse(decodeURIComponent(String(token || ''))); } catch (_e) { return null; }
};
const withState = (text, state) => {
  return text;
};
const recoverStateFromRaw = (obj) => {
  let blob = '';
  try { blob = JSON.stringify(obj || {}); } catch (_e) { blob = ''; }
  if (!blob) return null;
  // Backward compatibility: old visible HTML marker.
  const oldRe = /<!--FR_STATE:([\\s\\S]*?)-->/g;
  let oldM;
  let oldLast = null;
  while ((oldM = oldRe.exec(blob)) !== null) {
    if (oldM[1]) oldLast = oldM[1];
  }
  if (oldLast) return decodeState(oldLast);
  return null;
};

const questions = [
  { field: 'problema', text: 'Qual problema ou oportunidade essa alteracao resolve?' },
  { field: 'mudanca', text: 'Descreva a mudanca como voce espera ver no produto.' },
  { field: 'evidencias', text: 'Quais evidencias/criterios de aceite comprovam que a entrega esta pronta? (lista: uma por linha, ou separadas por ";")' },
  { field: 'restricoes', text: 'Limites de prazo, compliance, integracoes proibidas, etc. (lista: uma por linha, ou separadas por ";")' },
];
const questionNorms = questions.map((q) => norm(q.text));

const emptyIntake = () => ({
  step: 0,
  problema: '',
  mudanca: '',
  evidencias: [],
  restricoes: [],
  status: '',
  diagnostico: '',
  evidencias_lista: [],
});

const parseList = (input) =>
  toStr(input)
    .split(/\n|;|\|/g)
    .map((s) => toStr(s).replace(/^[-*\d.)\s]+/, ''))
    .filter(Boolean);

const askQuestion = (step) => {
  const idx = Math.max(0, Math.min(Number(step || 0), questions.length - 1));
  return questions[idx].text;
};

const isGreeting = (v) => {
  const t = norm(v);
  return ['oi', 'ola', 'olá', 'hello', 'hey', 'bom dia', 'boa tarde', 'boa noite'].includes(t);
};
const inferLastAskedStepFromRaw = (obj) => {
  let blob = '';
  try { blob = norm(JSON.stringify(obj || {})); } catch (_e) { blob = ''; }
  if (!blob) return -1;
  let last = -1;
  for (let i = 0; i < questionNorms.length; i++) {
    if (blob.includes(questionNorms[i])) last = i;
  }
  return last;
};

if (!message) {
  // If parser failed but intake mode is active, keep the flow progressing
  // instead of sending user back to menu.
  if (chatModeGlobal() === 'impact_intake') {
    const state = impactIntakeGlobal() || emptyIntake();
    return [{ json: { option: '1', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: askQuestion(state.step) } }];
  }
  writeState('menuShownGlobal', true);
  return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: menuText } }];
}

const lower = norm(message);
if (lower === '/reset') {
  writeState('chatModeGlobal', '');
  writeState('impactIntakeGlobal', null);
  writeState('menuShownGlobal', false);
  return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: menuText } }];
}

if (lower === '/menu') {
  writeState('chatModeGlobal', '');
  writeState('impactIntakeGlobal', null);
  writeState('menuShownGlobal', true);
  return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: menuText } }];
}

pushMemory('user', message);

const optionMatch = lower.match(/^([123])\s*[\).:-]?\s*$/);
if (optionMatch) {
  const opt = optionMatch[1];
  writeState('menuShownGlobal', true);

  if (opt === '1') {
    writeState('chatModeGlobal', 'impact_intake');
    const st = emptyIntake();
    writeState('impactIntakeGlobal', st);
    return [{ json: { option: '1', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: withState(askQuestion(0), st) } }];
  }

  if (opt === '2') {
    writeState('chatModeGlobal', 'pr_qa');
    return [{ json: { option: '2', route: 'pr_qa', session_id: sessionId, chat_history: chatHistory(), output: 'Opcao 2 selecionada. Agora descreva sua duvida sobre funcionalidade ja implementada.' } }];
  }

  writeState('chatModeGlobal', 'correction_propose');
  return [{ json: { option: '3', route: 'correction_propose', session_id: sessionId, chat_history: chatHistory(), output: 'Opcao 3 selecionada. Agora descreva a correcao desejada nas PRs abertas.' } }];
}

if (!menuShownGlobal()) {
  writeState('menuShownGlobal', true);
}

if (chatModeGlobal() === 'impact_intake') {
  const state = impactIntakeGlobal() || emptyIntake();
  const idx = Math.max(0, Math.min(Number(state.step || 0), questions.length - 1));
  const field = questions[idx].field;

  if (field === 'evidencias' || field === 'restricoes') state[field] = parseList(message);
  else state[field] = toStr(message);

  state.step = idx + 1;

  if (state.step >= questions.length) {
    const evidenciasLista = Array.isArray(state.evidencias) ? state.evidencias : [];
    const restricoesLista = Array.isArray(state.restricoes) ? state.restricoes : [];

    writeState('chatModeGlobal', '');
    writeState('impactIntakeGlobal', null);

    return [{
      json: {
        option: '1',
        route: 'impact_ready',
        ready_for_impact: true,
        session_id: sessionId,
        chat_history: chatHistory(),
        problema: toStr(state.problema),
        mudanca: toStr(state.mudanca),
        evidencias: evidenciasLista.join('; '),
        restricoes: restricoesLista.join('; '),
        status: toStr(state.status),
        diagnostico: toStr(state.diagnostico),
        evidencias_lista: evidenciasLista,
        restricoes_lista: restricoesLista,
      }
    }];
  }

  writeState('impactIntakeGlobal', state);
  return [{ json: { option: '1', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: withState(askQuestion(state.step), state) } }];
}

if (chatModeGlobal() === 'pr_qa') {
  return [{
    json: {
      option: '2',
      route: 'pr_qa',
      session_id: sessionId,
      chat_history: chatHistory(),
      question: message,
      owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
      github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
      llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
    }
  }];
}

if (chatModeGlobal() === 'correction_propose') {
  return [{
    json: {
      option: '3',
      route: 'correction_propose',
      session_id: sessionId,
      chat_history: chatHistory(),
      question: message,
      owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
      github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
      llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
    }
  }];
}

// Recovery branch: if no mode and user sends non-option text, assume intake option 1.
if (!isGreeting(message)) {
  let state = recoverStateFromRaw(raw);
  if (!state || typeof state !== 'object') {
    state = emptyIntake();
    const inferred = inferLastAskedStepFromRaw(raw);
    if (inferred >= 0 && inferred < questions.length) {
      // If we can detect the last asked question from payload context,
      // current user message is the answer to that question.
      state.step = inferred;
    }
  }
  if (!Number.isFinite(Number(state.step))) state.step = 0;

  const idx = Math.max(0, Math.min(Number(state.step || 0), questions.length - 1));
  const field = questions[idx].field;
  if (field === 'evidencias' || field === 'restricoes') state[field] = parseList(message);
  else state[field] = toStr(message);

  state.step = idx + 1;

  if (state.step >= questions.length) {
    const evidenciasLista = Array.isArray(state.evidencias) ? state.evidencias : [];
    const restricoesLista = Array.isArray(state.restricoes) ? state.restricoes : [];
    writeState('chatModeGlobal', '');
    writeState('impactIntakeGlobal', null);
    return [{
      json: {
        option: '1',
        route: 'impact_ready',
        ready_for_impact: true,
        session_id: sessionId,
        chat_history: chatHistory(),
        problema: toStr(state.problema),
        mudanca: toStr(state.mudanca),
        evidencias: evidenciasLista.join('; '),
        restricoes: restricoesLista.join('; '),
        status: toStr(state.status),
        diagnostico: toStr(state.diagnostico),
        evidencias_lista: evidenciasLista,
        restricoes_lista: restricoesLista,
      }
    }];
  }

  writeState('chatModeGlobal', 'impact_intake');
  writeState('impactIntakeGlobal', state);
  return [{ json: { option: '1', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: withState(askQuestion(state.step), state) } }];
}

return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: menuText } }];

const out = String($json.output ?? '').trim();
return [{ json: { output: out || 'Escolha uma opcao para continuar (envie apenas 1, 2 ou 3):
1) Nova analise de Impacto
2) Duvida sobre funcionalidade ja implementada
3) Correcao de PRs abertas' } }];
